graphql.query:
query GetCurrencies {
  currencies {
    id
    code
    name
    symbol
  }
}

query GetExchangeRates {
  exchangeRates {
    id
    fromCurrency { code symbol }
    toCurrency { code symbol }
    buyRate
    sellRate
    createdAt
  }
}

query ConvertDOPtoUSD {
  convertCurrency(amount: 5900, from: "DOP", to: "USD") {
    fromCurrency
    toCurrency
    originalAmount
    convertedAmount
    rateUsed
    rateType
  }
}

query ConvertUSDtoDOP {
  convertCurrency(amount: 100, from: "USD", to: "DOP") {
    fromCurrency
    toCurrency
    originalAmount
    convertedAmount
    rateUsed
    rateType
  }
}

query ConvertEURtoUSD {
  convertCurrency(amount: 100, from: "EUR", to: "USD") {
    fromCurrency
    toCurrency
    originalAmount
    convertedAmount
    rateUsed
    rateType
  }
}

query ConvertSameCurrency {
  convertCurrency(amount: 1000, from: "DOP", to: "DOP") {
    fromCurrency
    toCurrency
    originalAmount
    convertedAmount
    rateUsed
    rateType
  }
}

query GetClients {
  clients {
    id
    firstName
    lastName
    email
    documentId
    phone
    isActive
    accounts {
      id
      accountNumber
      balance
      currency
      status
    }
    createdAt
  }
}

query GetClient($id: ID!) {
  client(id: $id) {
    id
    firstName
    lastName
    email
    documentId
    isActive
    accounts {
      id
      accountNumber
      balance
      currency
    }
  }
}

mutation CreateClient {
  createClient(input: {
    firstName: "Pedro"
    lastName: "Martínez"
    email: "pedro.martinez@email.com"
    documentId: "001-9999999-9"
    phone: "809-555-0099"
  }) {
    id
    firstName
    lastName
    email
    documentId
    isActive
    createdAt
  }
}

mutation CreateClientDuplicateEmail {
  createClient(input: {
    firstName: "Pedro"
    lastName: "Martínez"
    email: "pedro.martinez@email.com"
    documentId: "001-0000000-0"
  }) {
    id
  }
}

mutation CreateClientInvalidEmail {
  createClient(input: {
    firstName: "Test"
    lastName: "User"
    email: "not-an-email"
    documentId: "001-1111111-0"
  }) {
    id
  }
}

mutation UpdateClient($id: ID!) {
  updateClient(id: $id, input: {
    phone: "809-111-9999"
    firstName: "Pedro José"
  }) {
    id
    firstName
    phone
    updatedAt
  }
}

mutation RemoveClient($id: ID!) {
  removeClient(id: $id)
}

query GetClientNotFound {
  client(id: "00000000-0000-0000-0000-000000000000") {
    id
    firstName
  }
}

query GetAccounts {
  accounts {
    id
    accountNumber
    balance
    currency
    status
    client {
      id
      firstName
      lastName
    }
    createdAt
  }
}

query GetAccount($id: ID!) {
  account(id: $id) {
    id
    accountNumber
    balance
    currency
    status
    client {
      firstName
      lastName
      email
    }
  }
}

query GetAccountsByClient($clientId: ID!) {
  accountsByClient(clientId: $clientId) {
    id
    accountNumber
    balance
    currency
    status
  }
}

mutation CreateAccountDOP($clientId: String!) {
  createAccount(input: {
    clientId: $clientId
    currency: "DOP"
  }) {
    id
    accountNumber
    balance
    currency
    status
    client { firstName }
  }
}

mutation CreateAccountUSD($clientId: String!) {
  createAccount(input: {
    clientId: $clientId
    currency: "USD"
  }) {
    id
    accountNumber
    balance
    currency
    status
  }
}

query GetTransactions {
  transactions {
    id
    type
    amount
    currency
    exchangeRate
    convertedAmount
    rateType
    destinationCurrency
    description
    sourceAccount {
      id
      accountNumber
      currency
    }
    destinationAccount {
      id
      accountNumber
      currency
    }
    createdAt
  }
}

query GetTransactionsByAccount($accountId: ID!) {
  transactionsByAccount(accountId: $accountId) {
    id
    type
    amount
    currency
    description
    createdAt
  }
}

mutation DepositDOP($accountId: String!) {
  deposit(input: {
    accountId: $accountId
    amount: 10000
    currency: "DOP"
    description: "Depósito nómina"
  }) {
    id
    type
    amount
    currency
    description
    sourceAccount {
      accountNumber
      balance
      currency
    }
    createdAt
  }
}

mutation DepositUSD($accountId: String!) {
  deposit(input: {
    accountId: $accountId
    amount: 500
    currency: "USD"
    description: "Wire transfer recibido"
  }) {
    id
    type
    amount
    currency
    sourceAccount { balance currency }
    createdAt
  }
}

mutation WithdrawalDOP($accountId: String!) {
  withdrawal(input: {
    accountId: $accountId
    amount: 2000
    description: "Retiro cajero automático"
  }) {
    id
    type
    amount
    currency
    description
    sourceAccount {
      accountNumber
      balance
    }
    createdAt
  }
}

mutation WithdrawalOverdraft($accountId: String!) {
  withdrawal(input: {
    accountId: $accountId
    amount: 9999999
    description: "Retiro imposible"
  }) {
    id
    type
    amount
  }
}

mutation TransferDOPtoDOP($sourceId: String!, $destId: String!) {
  transfer(input: {
    sourceAccountId: $sourceId
    destinationAccountId: $destId
    amount: 3000
    description: "Pago de alquiler"
  }) {
    id
    type
    amount
    currency
    exchangeRate
    convertedAmount
    rateType
    destinationCurrency
    description
    sourceAccount { accountNumber balance currency }
    destinationAccount { accountNumber balance currency }
    createdAt
  }
}

mutation TransferDOPtoUSD($sourceId: String!, $destId: String!) {
  transfer(input: {
    sourceAccountId: $sourceId
    destinationAccountId: $destId
    amount: 5900
    description: "Conversión DOP a USD"
  }) {
    id
    type
    amount
    currency
    exchangeRate
    convertedAmount
    rateType
    destinationCurrency
    description
    sourceAccount { accountNumber balance currency }
    destinationAccount { accountNumber balance currency }
    createdAt
  }
}

mutation TransferUSDtoDOP($sourceId: String!, $destId: String!) {
  transfer(input: {
    sourceAccountId: $sourceId
    destinationAccountId: $destId
    amount: 100
    description: "Conversión USD a DOP"
  }) {
    id
    type
    amount
    currency
    exchangeRate
    convertedAmount
    rateType
    destinationCurrency
    sourceAccount { balance currency }
    destinationAccount { balance currency }
    createdAt
  }
}

mutation TransferEURtoUSD($sourceId: String!, $destId: String!) {
  transfer(input: {
    sourceAccountId: $sourceId
    destinationAccountId: $destId
    amount: 100
    description: "Conversión EUR a USD"
  }) {
    id
    type
    amount
    currency
    exchangeRate
    convertedAmount
    rateType
    destinationCurrency
    sourceAccount { balance currency }
    destinationAccount { balance currency }
  }
}

mutation TransferNotFound {
  transfer(input: {
    sourceAccountId: "00000000-0000-0000-0000-000000000000"
    destinationAccountId: "00000000-0000-0000-0000-000000000001"
    amount: 100
  }) {
    id
    type
  }
}

query VerifyBalances($dopId: ID!, $usdId: ID!) {
  dopAccount: account(id: $dopId) {
    accountNumber
    balance
    currency
  }
  usdAccount: account(id: $usdId) {
    accountNumber
    balance
    currency
  }
}

query SearchTransfer {
  searchTransactions(query: "TRANSFER")
}

query SearchUSD {
  searchTransactions(query: "USD")
}

query SearchByDescription {
  searchTransactions(query: "nómina")
}

query SearchDeposit {
  searchTransactions(query: "DEPOSIT")
}

query AllTransactionsFirst {
  transactions {
    id
    type
    amount
    currency
  }
}

query AllTransactionsSecond {
  transactions {
    id
    type
    amount
    currency
  }
}
